    std::uint64_t aNonceWordE = TwistMix64::DiffuseB(pNonce * 0xEA6C71D7EE7097ABULL + 0x9B0FCD918B47BBA5ULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xD6B7C2E0F86E1661ULL + 0xB8449C6C5CF87EE3ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0x8F295F05495FEFC1ULL + 0xD76F4BB066D5989BULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0x9E9B83582E617D0DULL + 0x91DD9918C200E95CULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0xF4A78996B9C36E2DULL + 0xE8040CC1E9022A4EULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xFE605E60E1A53655ULL + 0xDBCCA71528C22926ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseB(pNonce * 0x8BFD50BEBEF8058FULL + 0xF764F93660F4D67BULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseB(pNonce * 0xDD5B8E4DC04AFF55ULL + 0xDC0B7A830AD37328ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0xE58F27DCE4D93AE9ULL + 0xFFC7CAB807BB94ACULL);
