            aOrbiterB = (aWandererI + RotL64(aPrevious, 47U)) + 4460164640123106420U;
            aOrbiterK = ((((aWandererJ + RotL64(aIngress, 26U)) + RotL64(aCarry, 3U)) + 2841354151958020759U) + aOrbiterAssignSaltB[((aIndex + 15U)) & S_SALT1]) + aNonceWordL;
