            aOrbiterA = ((((aWandererG + RotL64(aPrevious, 22U)) + RotL64(aCarry, 23U)) + 15311539514898869291U) + aOrbiterAssignSaltA[(((31U - aIndex) + 8U)) & S_SALT1]) + aNonceWordO;
