            //
            aOrbiterE = (aOrbiterE + aOrbiterI) + 4589299298454123615U;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 14239239654656942173U;
            aOrbiterF = RotL64((aOrbiterF * 14202703720950602457U), 41U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterH) + 2255905598955545554U) + aNonceWordF;
            aOrbiterD = (aOrbiterD ^ aOrbiterF) ^ 18285699121808008246U;
            aOrbiterD = RotL64((aOrbiterD * 7528629304846310171U), 29U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterF) + 6633031416060461856U;
            aOrbiterG = (aOrbiterG ^ aOrbiterC) ^ 17851199631067988694U;
            aOrbiterG = RotL64((aOrbiterG * 9377699541570724265U), 39U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterK) + 1111129698102797143U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterA) ^ 10458495537825936482U;
            aOrbiterJ = RotL64((aOrbiterJ * 3969844654063568595U), 53U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterB) + 12661674195159255387U) + aOrbiterUpdateSaltE[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterH) ^ 11256447382286538245U;
            aOrbiterA = RotL64((aOrbiterA * 9372783897760361121U), 19U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterJ) + 13966897156585154198U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterI) ^ 1397256030531571318U) ^ aNonceWordN;
            aOrbiterH = RotL64((aOrbiterH * 3702887270955702595U), 37U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterA) + 3351396493997582621U) + aNonceWordJ;
            aOrbiterI = (aOrbiterI ^ aOrbiterD) ^ 2814829177022563515U;
            aOrbiterI = RotL64((aOrbiterI * 17394933074083352657U), 47U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterE) + 15054747478724280955U) + aOrbiterUpdateSaltF[((aIndex + 29U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterK) ^ 12765331190382832908U;
