            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 12696293275646292856U;
            aOrbiterB = (aOrbiterB ^ aOrbiterJ) ^ 17464223608400698949U;
            aOrbiterB = RotL64((aOrbiterB * 13130313362607896309U), 13U);
            //
            aIngress = aOrbiterI ^ RotL64(aOrbiterB, 38U);
