            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterF, 53U));
            aIngress = aIngress + (RotL64(aOrbiterE, 11U) ^ aOrbiterK);
            aIngress = aIngress + RotL64(aOrbiterH, 46U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererG = aWandererG + (((RotL64(aScatter, 35U) + RotL64(aOrbiterH, 29U)) + aOrbiterB) + aWandererUpdateSaltF[((aIndex + 19U)) & S_SALT1]);
            aWandererF = aWandererF ^ (((RotL64(aIngress, 53U) + aOrbiterF) + RotL64(aOrbiterD, 6U)) + aNonceWordH);
            aWandererE = aWandererE + ((RotL64(aCross, 6U) + aOrbiterJ) + RotL64(aOrbiterC, 23U));
            aWandererK = aWandererK ^ ((RotL64(aPrevious, 21U) + aOrbiterC) + RotL64(aOrbiterA, 41U));
