            aOrbiterJ = RotL64((aOrbiterJ * 1999172472537578919U), 35U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterA) + 8276518280473193601U;
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 15202548275845711090U;
            aOrbiterD = RotL64((aOrbiterD * 9514306199576042059U), 23U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterC) + 12958403436464029144U) + aNonceWordK;
